blocks.body:
{
    "level": "B2",
    "intro": "W tej lekcji poznasz <strong>Future Continuous Passive</strong>. To forma poprawna gramatycznie, ale w praktyce <strong>bardzo rzadko używana</strong>, bo brzmi ciężko i ma mało naturalny rytm.",
    "rules": [
        {
            "label": "Formuła",
            "color": "emerald",
            "text": "Podstawowy wzór to <strong>subject + will be being + V3</strong>.",
            "example": "The house will be being painted at this time tomorrow."
        },
        {
            "label": "Przeczenie",
            "color": "rose",
            "text": "Forma przecząca to <strong>subject + will not be being + V3</strong>.",
            "example": "The report will not be being written at that moment."
        },
        {
            "label": "Uwaga",
            "color": "amber",
            "text": "W codziennej komunikacji częściej wybieramy <strong>Future Simple Passive</strong> albo stronę czynną.",
            "example": "Częściej powiesz: The house will be painted tomorrow."
        }
    ]
}

{
    "title": "1. Struktura formy",
    "intro": "Dla wszystkich osób używamy tej samej sekwencji: <strong>will be being + V3</strong>.",
    "items": [
        {
            "label": "Wszystkie osoby",
            "title": "will be being + V3",
            "subtitle": "I / you / he / she / it / we / they will be being interviewed."
        },
        {
            "label": "Liczba pojedyncza",
            "title": "will be being + V3",
            "subtitle": "The car will be being repaired."
        },
        {
            "label": "Liczba mnoga",
            "title": "will be being + V3",
            "subtitle": "The documents will be being reviewed."
        },
        {
            "label": "Dlaczego to rzadkie?",
            "title": "trzy elementy z rzędu",
            "subtitle": "will + be + being + V3 brzmi ciężko i nienaturalnie"
        }
    ]
}

{
    "title": "2. Zdania twierdzące",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "Używamy wzoru <strong>subject + will be being + V3</strong>, gdy chcemy mówić o trwającym procesie w przyszłości z perspektywy strony biernej.",
            "examples": [
                {
                    "en": "The house will be being painted at this time tomorrow.",
                    "ua": "Jutro o tej porze dom będzie w trakcie malowania."
                },
                {
                    "en": "The project will be being discussed at 3 PM.",
                    "ua": "O 15:00 projekt będzie omawiany."
                },
                {
                    "en": "The documents will be being reviewed all day.",
                    "ua": "Dokumenty będą przeglądane przez cały dzień."
                }
            ]
        },
        {
            "label": "Lepsza praktyka",
            "color": "amber",
            "description": "W realnej komunikacji zwykle wybieramy <strong>prostszą alternatywę</strong>.",
            "examples": [
                {
                    "en": "The house will be painted tomorrow.",
                    "ua": "To naturalniejsza wersja z Future Simple Passive."
                },
                {
                    "en": "They will be painting the house.",
                    "ua": "Bardzo często jeszcze lepiej brzmi strona czynna."
                }
            ]
        }
    ]
}

{
    "title": "3. Kiedy tej formy użyć?",
    "sections": [
        {
            "label": "Moment w przyszłości",
            "color": "emerald",
            "description": "Teoretycznie forma ta pokazuje, że czynność będzie <strong>w toku</strong> w określonym momencie przyszłości.",
            "examples": [
                {
                    "en": "At 10 AM tomorrow, the meeting will be being held.",
                    "ua": "Jutro o 10:00 spotkanie będzie właśnie trwało."
                },
                {
                    "en": "This time next week, the building will be being renovated.",
                    "ua": "W przyszłym tygodniu o tej porze budynek będzie w trakcie remontu."
                }
            ]
        },
        {
            "label": "Dlaczego zwykle jej unikamy",
            "color": "rose",
            "description": "Problemem nie jest gramatyczna poprawność, ale <strong>nienaturalne brzmienie</strong>.",
            "examples": [
                {
                    "en": "The sequence will be being sounds clumsy.",
                    "ua": "Sekwencja <strong>will be being</strong> brzmi ciężko."
                },
                {
                    "en": "There is almost always a simpler alternative.",
                    "ua": "Prawie zawsze da się powiedzieć to prościej."
                },
                {
                    "en": "It is mostly useful for recognition, not production.",
                    "ua": "Najważniejsze to rozumieć tę formę, gdy ją zobaczysz."
                }
            ]
        }
    ]
}

{
    "title": "4. Zdania przeczące",
    "sections": [
        {
            "label": "Struktura",
            "color": "rose",
            "description": "Przeczenie tworzymy według wzoru <strong>subject + will not be being + V3</strong>.",
            "examples": [
                {
                    "en": "The report will not be being written at that moment.",
                    "ua": "W tym momencie raport nie będzie jeszcze pisany."
                },
                {
                    "en": "The car will not be being repaired tomorrow afternoon.",
                    "ua": "Jutro po południu samochód nie będzie akurat naprawiany."
                }
            ]
        },
        {
            "label": "Skrót",
            "color": "amber",
            "description": "W teorii możliwe jest także <strong>won't be being + V3</strong>, ale brzmi to jeszcze mniej naturalnie.",
            "examples": [
                {
                    "en": "The documents won't be being processed then.",
                    "ua": "Tę wersję lepiej traktować jako ciekawostkę gramatyczną."
                }
            ]
        }
    ]
}

{
    "title": "5. Zdania pytające",
    "sections": [
        {
            "label": "Pytania yes / no",
            "color": "blue",
            "description": "Używamy wzoru <strong>Will + subject + be being + V3?</strong>",
            "examples": [
                {
                    "en": "Will the house be being painted at that time?",
                    "ua": "Czy o tej porze dom będzie właśnie malowany?"
                },
                {
                    "en": "Will the project be being discussed tomorrow?",
                    "ua": "Czy jutro projekt będzie omawiany?"
                }
            ]
        },
        {
            "label": "Pytania wh-",
            "color": "sky",
            "description": "W pytaniach szczegółowych dodajemy słowo pytające przed <strong>will</strong>.",
            "examples": [
                {
                    "en": "What will be being done at 5 PM?",
                    "ua": "Co będzie robione o 17:00?"
                },
                {
                    "en": "Where will the meeting be being held?",
                    "ua": "Gdzie będzie się wtedy odbywać spotkanie?"
                }
            ]
        }
    ]
}

{
    "title": "6. Lepsze alternatywy",
    "intro": "Najczęściej zamiast Future Continuous Passive użyj jednej z tych opcji:",
    "rows": [
        {
            "en": "❌ The house will be being painted.",
            "ua": "Forma poprawna, ale ciężka w odbiorze.",
            "note": "✅ The house will be painted."
        },
        {
            "en": "❌ The report will be being written.",
            "ua": "Brzmi technicznie i nienaturalnie.",
            "note": "✅ They will be writing the report."
        },
        {
            "en": "❌ The car will be being repaired.",
            "ua": "To konstrukcja, której zwykle da się uniknąć.",
            "note": "✅ The car will be repaired. / The car is going to be repaired."
        }
    ],
    "warning": "📌 W praktyce najczęściej wygrywa <strong>Future Simple Passive</strong> albo <strong>Future Continuous Active</strong>."
}

{
    "title": "7. Active vs passive",
    "intro": "Porównaj stronę czynną i bierną w podobnym znaczeniu:",
    "rows": [
        {
            "en": "Active: They will be painting the house.",
            "ua": "Będą malować dom.",
            "note": "→ Passive: The house will be being painted. (bardzo rzadko)"
        },
        {
            "en": "Active: We will be discussing the project.",
            "ua": "Będziemy omawiać projekt.",
            "note": "→ Passive: The project will be being discussed. (bardzo rzadko)"
        },
        {
            "en": "Active: Someone will be repairing the car.",
            "ua": "Ktoś będzie naprawiał samochód.",
            "note": "→ Passive: The car will be being repaired. (bardzo rzadko)"
        }
    ],
    "warning": "📌 W większości sytuacji strona czynna brzmi tu naturalniej."
}

{
    "title": "8. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pomijanie being.",
            "wrong": "The house will be painted now. (jeśli chodzi o proces)",
            "right": "✅ The house will be being painted now."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Zła kolejność wyrazów.",
            "wrong": "The report will being be written.",
            "right": "✅ The report will be being written."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Mylenie been i being.",
            "wrong": "The car will be been repaired.",
            "right": "✅ The car will be being repaired."
        },
        {
            "label": "Rada",
            "color": "emerald",
            "title": "Wybieraj prostszą formę, gdy to możliwe.",
            "wrong": "Upieranie się przy Future Continuous Passive w każdej sytuacji.",
            "right": "✅ Często lepiej użyć Future Simple Passive albo strony czynnej."
        }
    ]
}
